import Foundation

// Auto-generated CGRC question bank (59 items)
let BANK: [Question] = [
    Question(id: 0, domain: 1, text: "Which NIST publication is the catalog of security and privacy controls used to build a control baseline?", options: ["NIST SP 800-37", "NIST SP 800-53", "NIST SP 800-30", "NIST SP 800-60"], answer: 1, explain: "SP 800-53 is the control catalog. 800-37 is the RMF process, 800-30 is risk assessment guidance, 800-60 maps information types to impact."),
    Question(id: 1, domain: 1, text: "In governance, risk, and compliance, what does 'governance' primarily establish?", options: ["The technical configuration of controls", "Direction, oversight, and accountability aligning security with organizational objectives", "The schedule for vulnerability scans", "The list of residual risks"], answer: 1, explain: "Governance sets strategic direction, oversight, roles, and accountability so security/privacy align with business goals."),
    Question(id: 2, domain: 1, text: "Which law requires U.S. federal agencies to develop and maintain an information security program?", options: ["HIPAA", "GDPR", "FISMA", "PCI-DSS"], answer: 2, explain: "FISMA (Federal Information Security Modernization Act) mandates agency-wide information security programs."),
    Question(id: 3, domain: 1, text: "The triad of confidentiality, integrity, and availability is most directly concerned with:", options: ["Budget allocation", "Protecting information and systems", "Marketing security products", "Hiring practices"], answer: 1, explain: "The CIA triad describes the fundamental security objectives for protecting information and systems."),
    Question(id: 4, domain: 1, text: "Which framework is a governance and management framework for enterprise IT developed by ISACA?", options: ["COBIT", "FedRAMP", "FIPS 199", "NIST CSF"], answer: 0, explain: "COBIT (Control Objectives for Information and Related Technology) is ISACA's IT governance framework."),
    Question(id: 5, domain: 1, text: "Non-repudiation provides assurance that:", options: ["Data is encrypted at rest", "A party cannot deny having performed an action", "Systems are always available", "Access is role-based"], answer: 1, explain: "Non-repudiation prevents an actor from denying the authenticity of their action, e.g., via digital signatures."),
    Question(id: 6, domain: 1, text: "FedRAMP primarily governs the security authorization of:", options: ["Medical devices", "Cloud products and services used by federal agencies", "Payment card terminals", "Industrial control systems"], answer: 1, explain: "FedRAMP standardizes security assessment and authorization for cloud services used by the U.S. government."),
    Question(id: 7, domain: 1, text: "Which regulation governs the protection of personal data of individuals in the European Union?", options: ["HIPAA", "GDPR", "SOX", "GLBA"], answer: 1, explain: "The General Data Protection Regulation (GDPR) governs personal data protection in the EU."),
    Question(id: 8, domain: 1, text: "The phase of the SDLC where the system is removed from operation and data is sanitized is:", options: ["Development", "Operations & maintenance", "Disposal", "Design"], answer: 2, explain: "Disposal (decommissioning) covers removal from operation and sanitization/destruction of data and media."),
    Question(id: 9, domain: 1, text: "PCI-DSS applies to organizations that:", options: ["Process, store, or transmit payment card data", "Handle protected health information", "Operate cloud services for the government", "Manage classified national security systems"], answer: 0, explain: "PCI-DSS sets requirements for any entity handling cardholder data."),
    Question(id: 10, domain: 2, text: "FIPS 199 is used to:", options: ["Select specific controls", "Categorize information systems by impact level", "Authorize a system to operate", "Assess control effectiveness"], answer: 1, explain: "FIPS 199 establishes security categorization (low/moderate/high) based on impact to CIA."),
    Question(id: 11, domain: 2, text: "When categorizing a system under FIPS 199, the overall impact level is determined by:", options: ["The average of the three CIA impact values", "The lowest of the CIA impact values", "The highest of the CIA impact values (high-water mark)", "The availability value only"], answer: 2, explain: "FIPS 199 uses the high-water mark: the system's impact level equals the highest impact among C, I, and A."),
    Question(id: 12, domain: 2, text: "Which NIST publication helps map information types to provisional impact levels?", options: ["SP 800-53", "SP 800-60", "SP 800-137", "SP 800-18"], answer: 1, explain: "SP 800-60 provides guidance for mapping information types to security categories/impact levels."),
    Question(id: 13, domain: 2, text: "Defining the authorization boundary of a system primarily determines:", options: ["Which staff get raises", "What is included within the scope of the system being assessed and authorized", "The encryption algorithm", "The patch cadence"], answer: 1, explain: "The authorization boundary scopes the components, data, and interconnections covered by the authorization."),
    Question(id: 14, domain: 2, text: "A Data Protection Impact Assessment (DPIA) is most associated with:", options: ["Evaluating privacy risks of processing personal data", "Calculating system uptime", "Selecting a cloud provider", "Scheduling penetration tests"], answer: 0, explain: "A DPIA assesses risks to individuals from processing personal data and is referenced under privacy regimes like GDPR."),
    Question(id: 15, domain: 2, text: "Which document captures the system's name, purpose, functionality, and boundary?", options: ["POA&M", "System description / System Security Plan", "Assessment report", "Risk response plan"], answer: 1, explain: "The system description (often within the SSP) documents name, purpose, functionality, and boundary."),
    Question(id: 16, domain: 2, text: "Identifying the information types processed, stored, or transmitted is necessary primarily to:", options: ["Set the help desk hours", "Determine security objectives and impact levels for the system", "Choose office locations", "Define the marketing plan"], answer: 1, explain: "Knowing information types drives the security categorization and applicable compliance requirements."),
    Question(id: 17, domain: 3, text: "A control baseline is best described as:", options: ["A finalized authorization decision", "A predefined starting set of controls for a given impact level", "A list of residual risks", "An incident response runbook"], answer: 1, explain: "Baselines (low/moderate/high in SP 800-53B) are predefined starting control sets tailored to the system."),
    Question(id: 18, domain: 3, text: "Tailoring a baseline may include all of the following EXCEPT:", options: ["Applying overlays", "Adding compensating controls", "Scoping out non-applicable controls", "Ignoring the authorizing official's risk tolerance"], answer: 3, explain: "Tailoring must reflect organizational risk tolerance; you cannot ignore the AO's risk guidance."),
    Question(id: 19, domain: 3, text: "An 'overlay' in control selection is:", options: ["A network diagram", "A specification of controls tailored for a community, technology, or environment", "A penetration test report", "A type of firewall rule"], answer: 1, explain: "Overlays provide a tailored set of controls for specific communities of interest, technologies, or environments."),
    Question(id: 20, domain: 3, text: "Inherited (common) controls are:", options: ["Controls implemented and managed by an entity other than the system, available for reuse", "Controls unique to one application", "Controls that cannot be assessed", "Controls that are always optional"], answer: 0, explain: "Common/inherited controls are provided by a separate entity (e.g., the enterprise) and inherited by many systems."),
    Question(id: 21, domain: 3, text: "A compensating control is used when:", options: ["A primary control cannot be implemented and an alternate provides equivalent protection", "No risk exists", "The system is decommissioned", "The AO is unavailable"], answer: 0, explain: "Compensating controls provide comparable protection when a baseline control is not feasible."),
    Question(id: 22, domain: 3, text: "Which document records the controls selected and how they are intended to be implemented?", options: ["System Security Plan (SSP)", "Penetration test report", "Memorandum of Understanding", "Contingency plan"], answer: 0, explain: "The SSP documents selected controls, implementation approach, and responsibilities."),
    Question(id: 23, domain: 3, text: "Stakeholder agreement on control allocation is important because:", options: ["It sets the WiFi password", "It establishes who is responsible for implementing and maintaining each control", "It determines the lunch schedule", "It selects the SIEM vendor"], answer: 1, explain: "Allocation assigns responsibility for each control to system, common, or hybrid providers with stakeholder concurrence."),
    Question(id: 24, domain: 3, text: "A continued-compliance strategy defined during selection typically includes:", options: ["Continuous monitoring and vulnerability management", "Only the initial assessment", "Decommissioning steps only", "Marketing activities"], answer: 0, explain: "Control selection should define how ongoing compliance (e.g., ConMon, vuln mgmt) will be sustained."),
    Question(id: 25, domain: 4, text: "A control classified as 'technical' is one that is:", options: ["Implemented through policies and procedures by people", "Implemented through hardware/software/firmware mechanisms", "Always inherited", "Never assessable"], answer: 1, explain: "Technical controls are implemented via technology mechanisms; management and operational controls are people/process oriented."),
    Question(id: 26, domain: 4, text: "A 'common control' during implementation is one that:", options: ["Is implemented once and inherited by multiple systems", "Must be reimplemented per system", "Cannot be documented", "Is the same as a compensating control"], answer: 0, explain: "Common controls are implemented at an enterprise level and inherited, reducing duplicate effort."),
    Question(id: 27, domain: 4, text: "During implementation, control implementations should be consistent with:", options: ["The vendor's marketing claims", "Compliance requirements and the documented control design", "The newest available product only", "Personal preference of the engineer"], answer: 1, explain: "Implementation must align with compliance requirements and the control design captured in the SSP."),
    Question(id: 28, domain: 4, text: "Which is an example of a management control?", options: ["Firewall ruleset", "Risk assessment policy and security planning", "Antivirus signature updates", "Disk encryption"], answer: 1, explain: "Management controls focus on risk management and oversight, e.g., policies, planning, and risk assessment."),
    Question(id: 29, domain: 4, text: "When a baseline control cannot be implemented as written, the appropriate action is to:", options: ["Skip it silently", "Implement a compensating/alternate control and document the rationale", "Decommission the system", "Lower the impact level arbitrarily"], answer: 1, explain: "Document and implement a compensating control with justification rather than leaving a gap undocumented."),
    Question(id: 30, domain: 4, text: "An implementation strategy should account for:", options: ["Resourcing, funding, timeline, and effectiveness", "Only the timeline", "Only the budget", "The CEO's travel plans"], answer: 0, explain: "A sound implementation strategy considers resources, funding, schedule, and expected effectiveness."),
    Question(id: 31, domain: 4, text: "Establishing the frequency for compliance documentation reviews and training during implementation supports:", options: ["Reducing user count", "Sustained, repeatable compliance over time", "Eliminating the SSP", "Avoiding assessments"], answer: 1, explain: "Defining review/training cadence ensures controls and documentation stay current and staff stay aware."),
    Question(id: 32, domain: 5, text: "The three primary assessment methods defined by NIST are:", options: ["Interview, examine, test", "Scan, patch, report", "Plan, do, check", "Avoid, accept, transfer"], answer: 0, explain: "SP 800-53A defines examine, interview, and test as the assessment methods."),
    Question(id: 33, domain: 5, text: "A POA&M (Plan of Action and Milestones) is used to:", options: ["Document weaknesses and the plan/timeline to remediate them", "Authorize a system permanently", "Replace the SSP", "Conduct penetration tests"], answer: 0, explain: "The POA&M tracks identified deficiencies, remediation actions, resources, and milestones."),
    Question(id: 34, domain: 5, text: "Which risk response means taking action to reduce the likelihood or impact of a risk?", options: ["Accept", "Mitigate", "Avoid", "Transfer"], answer: 1, explain: "Mitigation reduces risk via controls. Accept = tolerate; Avoid = stop the activity; Transfer/Share = shift to a third party."),
    Question(id: 35, domain: 5, text: "Transferring (sharing) a risk is typically accomplished by:", options: ["Buying insurance or using a third party/contract", "Ignoring it", "Patching the system", "Decommissioning the system"], answer: 0, explain: "Risk transfer/sharing shifts financial or operational risk, e.g., via insurance or outsourcing."),
    Question(id: 36, domain: 5, text: "Residual risk is:", options: ["Risk before any controls are applied", "Risk remaining after controls and responses are applied", "Risk that has been eliminated", "Risk that the AO never sees"], answer: 1, explain: "Residual risk is what remains after mitigations; the AO accepts it as part of authorization."),
    Question(id: 37, domain: 5, text: "The independence of the assessor (e.g., a 3PAO) matters because it:", options: ["Reduces objectivity", "Increases the credibility and objectivity of assessment results", "Eliminates the need for evidence", "Replaces the AO"], answer: 1, explain: "Assessor independence improves objectivity and the trustworthiness of the assessment findings."),
    Question(id: 38, domain: 5, text: "Which artifact records preliminary findings and risks discovered during the assessment?", options: ["Initial/Security Assessment Report (SAR)", "System decommissioning plan", "Change request", "Marketing brief"], answer: 0, explain: "The Security Assessment Report (SAR) documents findings, including preliminary and final results."),
    Question(id: 39, domain: 5, text: "Reassessing non-compliant findings after corrective action is applied is intended to:", options: ["Validate that the deficiency has been remediated", "Skip the AO", "Increase residual risk", "Avoid documentation"], answer: 0, explain: "Reassessment verifies corrective actions effectively addressed the finding before final reporting."),
    Question(id: 40, domain: 5, text: "Penetration testing, vulnerability scanning, and control testing fall under which assessment method?", options: ["Interview", "Examine", "Test", "Authorize"], answer: 2, explain: "These are 'test' methods that exercise controls to produce evidence of effectiveness."),
    Question(id: 41, domain: 5, text: "Prioritizing identified risks in the risk response plan primarily helps to:", options: ["Allocate limited resources to the most significant risks first", "Avoid all risk forever", "Eliminate the SSP", "Skip continuous monitoring"], answer: 0, explain: "Risk prioritization directs finite financial, personnel, and technical resources to the highest risks."),
    Question(id: 42, domain: 6, text: "The authorization decision (e.g., an ATO) is made by the:", options: ["Authorizing Official (AO)", "System administrator", "End user", "Help desk"], answer: 0, explain: "The Authorizing Official accepts residual risk and grants the Authorization to Operate."),
    Question(id: 43, domain: 6, text: "An Authorization to Operate (ATO) fundamentally represents:", options: ["A technical configuration", "A senior official's formal acceptance of risk to operate the system", "A vulnerability scan", "A vendor contract"], answer: 1, explain: "The ATO is the AO's formal, risk-based decision to accept residual risk and permit operation."),
    Question(id: 44, domain: 6, text: "The package submitted to support an authorization decision typically includes:", options: ["SSP, SAR, and POA&M", "Only the SSP", "Only marketing materials", "Only the network diagram"], answer: 0, explain: "The authorization package generally contains the SSP, the assessment report (SAR), and the POA&M."),
    Question(id: 45, domain: 6, text: "Determining the system risk posture requires:", options: ["Defining risk acceptance criteria and residual risk with stakeholder concurrence", "Ignoring residual risk", "Removing the AO from the process", "Skipping documentation"], answer: 0, explain: "Risk posture combines acceptance criteria, residual risk determination, and stakeholder agreement on treatment."),
    Question(id: 46, domain: 6, text: "If residual risk exceeds the AO's risk tolerance, a likely outcome is:", options: ["Automatic full ATO", "Denial of authorization or additional remediation required", "Immediate decommissioning regardless", "No action"], answer: 1, explain: "When risk is too high, the AO may deny authorization or require further remediation before approval."),
    Question(id: 47, domain: 6, text: "Formal notification of the compliance/authorization decision should be:", options: ["Kept secret from stakeholders", "Documented and shared with relevant stakeholders", "Sent only to the vendor", "Discarded"], answer: 1, explain: "The decision is formally documented and communicated to stakeholders responsible for the system."),
    Question(id: 48, domain: 6, text: "A common control provider's authorization package supports:", options: ["Inheritance of those controls by other systems", "Eliminating all assessments", "Bypassing the AO", "Marketing"], answer: 0, explain: "Authorizing common controls allows other systems to inherit and rely on them with documented assurance."),
    Question(id: 49, domain: 7, text: "Continuous monitoring (ConMon) guidance is provided primarily by:", options: ["NIST SP 800-137", "FIPS 199", "SP 800-60", "SP 800-18"], answer: 0, explain: "SP 800-137 covers Information Security Continuous Monitoring (ISCM)."),
    Question(id: 50, domain: 7, text: "A Change Control Board (CCB) is responsible for:", options: ["Reviewing and approving proposed system changes", "Running the help desk", "Performing penetration tests only", "Marketing the product"], answer: 0, explain: "The CCB evaluates, approves, and tracks changes, weighing impacts on risk and compliance."),
    Question(id: 51, domain: 7, text: "Before deploying an approved change to production, a best practice is to:", options: ["Have a rollback plan", "Delete the SSP", "Skip testing", "Disable logging"], answer: 0, explain: "Changes should be deployed with a rollback plan to recover if the change causes problems."),
    Question(id: 52, domain: 7, text: "The main purpose of ongoing continuous monitoring is to:", options: ["Maintain awareness of security posture and risk over time", "Replace the initial authorization", "Eliminate the need for controls", "Reduce documentation to zero"], answer: 0, explain: "ConMon sustains real-time awareness of security/privacy posture so risk decisions stay current."),
    Question(id: 53, domain: 7, text: "When legal, regulatory, or supplier requirements change, the monitoring strategy should be:", options: ["Left unchanged", "Revised to reflect the new requirements", "Deleted", "Ignored until the next ATO"], answer: 1, explain: "Monitoring strategies must be revised as legal, regulatory, supplier, and security/privacy requirements evolve."),
    Question(id: 54, domain: 7, text: "Proper system decommissioning includes:", options: ["Removing the system from operations and retaining/sharing documentation", "Leaving the system running indefinitely", "Skipping stakeholder review", "Destroying all records immediately without retention"], answer: 0, explain: "Decommissioning reviews requirements with stakeholders, removes the system, and retains required documentation."),
    Question(id: 55, domain: 7, text: "Ongoing security awareness and training during compliance maintenance should be:", options: ["Performed, documented, and retained", "Performed only once ever", "Optional and undocumented", "Replaced by the SAR"], answer: 0, explain: "Recurring training (incident response, contingency, annual security/privacy) must be performed and documented."),
    Question(id: 56, domain: 7, text: "An ATO that is maintained through continuous monitoring rather than fixed reauthorization dates is known as:", options: ["Ongoing authorization", "Denial of authorization", "Interim authorization to test", "Provisional decommissioning"], answer: 0, explain: "Ongoing authorization leverages robust ConMon so risk decisions are made continuously rather than periodically."),
    Question(id: 57, domain: 7, text: "Collecting evidence, updating documentation (e.g., SLAs, contracts, procedures), and communicating to stakeholders are part of:", options: ["Ongoing compliance activities", "Initial categorization", "Control selection only", "System scoping only"], answer: 0, explain: "These recurring tasks sustain compliance evidence and keep documentation and stakeholders current."),
    Question(id: 58, domain: 7, text: "Incident response and contingency activities during maintenance support:", options: ["Resilience and continued compliance of the operating system", "Marketing", "Avoiding the AO", "Eliminating monitoring"], answer: 0, explain: "Performing IR and contingency activities maintains resilience and demonstrates ongoing compliance."),
]
